import{_ as p,o as e,c as t,as as i}from"./chunks/framework.Dt0DMeWU.js";const d=JSON.parse('{"title":"第二章 VMware 的使用","description":"","frontmatter":{},"headers":[],"relativePath":"backend/Linux/02 第二章 VMware的使用.md","filePath":"backend/Linux/02 第二章 VMware的使用.md","lastUpdated":1775485159000}'),s={name:"backend/Linux/02 第二章 VMware的使用.md"};function l(c,o,n,a,g,r){return e(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="第二章-vmware-的使用" tabindex="-1">第二章 <code>VMware</code> 的使用 <a class="header-anchor" href="#第二章-vmware-的使用" aria-label="Permalink to &quot;第二章 `VMware` 的使用&quot;">​</a></h1><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to &quot;学习目标&quot;">​</a></h2><p><code>1</code> 熟悉 <code>VMware</code> 软件的作用!</p><p><code>2</code> 可以熟练安装 <code>VMware</code> 软件</p><p><code>3</code> 可以熟练使用 <code>VMware</code> 创建虚拟计算机</p><p><code>4</code> 可以熟练为虚拟计算机安装 <code>Linux</code> 操作系统</p><p><code>5</code> 能独立解决安装过程中的常见问题</p><h2 id="第一节-vmware-的作用" tabindex="-1">第一节 <code>VMware</code> 的作用 <a class="header-anchor" href="#第一节-vmware-的作用" aria-label="Permalink to &quot;第一节 `VMware` 的作用&quot;">​</a></h2><blockquote><p><code>VMware</code> 软件的作用</p></blockquote><p><img src="https://img.xbin.cn/blog/vm1_yFneoH7HVD.png" alt=""></p><ul><li><p>第一步，在 <code>Windows</code> 上安装 <code>VMware</code> 软件</p></li><li><p>第二步，使用 <code>VM</code> 软件创建虚拟的计算机</p></li><li><p>第三步，在虚拟的计算机上安装 <code>Linux</code> 操作系统</p></li></ul><h2 id="第二节-vmware-的安装" tabindex="-1">第二节 <code>VMware</code> 的安装 <a class="header-anchor" href="#第二节-vmware-的安装" aria-label="Permalink to &quot;第二节 `VMware` 的安装&quot;">​</a></h2><blockquote><p>安装前，先检查 <code>BIOS</code> 中是否开启了虚拟化支持</p></blockquote><ul><li>打开任务管理器，查看性能，<code>CPU</code> 部分，虚拟化处于“已启用”状态</li></ul><p><img src="https://img.xbin.cn/blog/vm01_ds4712mYIF.png" alt=""></p><ul><li>如果没有开启，则需要进入 <code>BIOS</code> 系统，将 <code>Virtualization Technology</code> 改为 <code>Enalble</code>，不同品牌的电脑进入 <code>BIOS</code> 的方式都不同，可以根据电脑品牌型号搜索对应的进入方式</li></ul><p><img src="https://img.xbin.cn/blog/vmwarework2_KdxMHe3eV0.png" alt=""></p><blockquote><p>第一步：下载 <code>VMware</code> 安装包(<a href="https://www.vmware.com/cn/products/workstation-pro/workstation-pro-evaluation.html" title="https://www.vmware.com/cn/products/workstation-pro/workstation-pro-evaluation.html" target="_blank" rel="noreferrer">https://www.vmware.com/cn/products/workstation-pro/workstation-pro-evaluation.html</a>)，双击开始安装</p></blockquote><p><img src="https://img.xbin.cn/blog/vm2_ds0WSj0iqI.png" alt=""></p><blockquote><p>第二步：点击下一步</p></blockquote><p><img src="https://img.xbin.cn/blog/vm4_xZNdpMkJz5.png" alt=""></p><p>第三步：同意协议，然后下一步</p><p><img src="https://img.xbin.cn/blog/vm6_6_VyL7CoIS.png" alt=""></p><blockquote><p>第四步：修改安装位置 勾选“添加到系统 <code>PATH</code>”</p></blockquote><p><img src="https://img.xbin.cn/blog/vm3_mXlDgwlXFg.png" alt=""></p><blockquote><p>第五步: 不检查更新，不参与客户体验提升计划</p></blockquote><p><img src="https://img.xbin.cn/blog/vm8b_rKulUL0IOp.png" alt=""></p><blockquote><p>第六步：勾选“桌面”和“开始菜单程序文件夹”</p></blockquote><p><img src="https://img.xbin.cn/blog/vm7_V5tSYT4LHD.png" alt=""></p><blockquote><p>第七步：开始安装</p></blockquote><p><img src="https://img.xbin.cn/blog/vm9_tFOK8LyFKx.png" alt=""></p><blockquote><p>第八步：安装完成</p></blockquote><p><img src="https://img.xbin.cn/blog/vm10_6PwKNVDRE8.png" alt=""></p><blockquote><p>第九步：点击桌面图标启动程序</p></blockquote><p><img src="https://img.xbin.cn/blog/vm8_AMhLZ3WcHm.png" alt=""></p><blockquote><p>第十步：购买软件后，获取许可证密钥，输入密钥即可正常使用</p></blockquote><p><img src="https://img.xbin.cn/blog/vm5_NVXW0CXCms.png" alt=""></p><p><img src="https://img.xbin.cn/blog/3_XgoPSawGP1.png" alt=""></p><h2 id="第三节-vmware-创建虚拟机" tabindex="-1">第三节 <code>VMware</code> 创建虚拟机 <a class="header-anchor" href="#第三节-vmware-创建虚拟机" aria-label="Permalink to &quot;第三节 `VMware` 创建虚拟机&quot;">​</a></h2><blockquote><p>第一步：选择创建新的虚拟计算机</p></blockquote><p><img src="https://img.xbin.cn/blog/1_E2b9FKparo.png" alt=""></p><blockquote><p>第二步：选择自定义</p></blockquote><p><img src="https://img.xbin.cn/blog/5_0p-x59bDMK.png" alt=""></p><blockquote><p>第三步： 硬件兼容选择 <code>Workstation</code> **.<code>x</code></p></blockquote><p><img src="https://img.xbin.cn/blog/6_96-sVPFqTT.png" alt=""></p><blockquote><p>第四步：选择稍后安装操作系统</p></blockquote><p><img src="https://img.xbin.cn/blog/7_z_xgQhLdnL.png" alt=""></p><blockquote><p>第五步：预选将来要安装的操作系统和版本</p></blockquote><p><img src="https://img.xbin.cn/blog/4_sGDWtzjz1Q.png" alt=""></p><blockquote><p>第六步：自定义虚拟机名称和虚拟机的存储位置</p></blockquote><p><img src="https://img.xbin.cn/blog/11_dkv7HM6FrC.png" alt=""></p><blockquote><p>第七步：设置虚拟计算机的 <code>CPU</code> 数量，不要高于宿主机的实际</p></blockquote><p><img src="https://img.xbin.cn/blog/2_7M-T6QlYUV.png" alt=""></p><blockquote><p>第八步：设置虚拟计算机内存，<code>2G</code> 即可</p></blockquote><p><img src="https://img.xbin.cn/blog/9_rQ4GQsGXqe.png" alt=""></p><blockquote><p>第九步：设置虚拟计算机初始网络连接方式，建议使用 <code>NAT</code> 模式</p></blockquote><p><img src="https://img.xbin.cn/blog/8_RwoBr48h0a.png" alt=""></p><blockquote><p>第十步：选择 <code>I</code>/<code>O</code> 控制器类型，默认推荐即可</p></blockquote><p><img src="https://img.xbin.cn/blog/12_-o_Mh0LR7Y.png" alt=""></p><blockquote><p>第十一步：选择磁盘类型，默认推荐即可</p></blockquote><p><img src="https://img.xbin.cn/blog/10_zi8pEWIwmJ.png" alt=""></p><blockquote><p>第十二步：选择创建新的虚拟磁盘</p></blockquote><p><img src="https://img.xbin.cn/blog/01_TzPAIAEmXg.png" alt=""></p><blockquote><p>第十三步：设定虚拟磁盘大小，并拆分成多个文件</p></blockquote><p><img src="https://img.xbin.cn/blog/13_LmRByJgteZ.png" alt=""></p><blockquote><p>第十四步：检查虚拟磁盘文件名，默认即可</p></blockquote><p><img src="https://img.xbin.cn/blog/15_mDLrLn8jvS.png" alt=""></p><blockquote><p>第十五步：检查虚拟计算机设置的信息，然后点击完成</p></blockquote><p><img src="https://img.xbin.cn/blog/4_SrKLpVDkwF.png" alt=""></p><blockquote><p>第十六步： 安装完成</p></blockquote><p><img src="https://img.xbin.cn/blog/2_jQoHqUJqEN.png" alt=""></p><h2 id="第四节-vmware-安装-linux" tabindex="-1">第四节 <code>VMware</code> 安装 <code>Linux</code> <a class="header-anchor" href="#第四节-vmware-安装-linux" aria-label="Permalink to &quot;第四节 `VMware` 安装 `Linux`&quot;">​</a></h2><blockquote><p>第一步：下载 <code>Linux</code> 的 <code>ISO</code> 镜像文件，这里选择的版本是 <code>Centos7 64</code> 位</p></blockquote><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">网易镜像：</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http://mirrors.163.com/centos/6/isos/</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http://mirrors.163.com/centos/7/isos/x86_64/</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">搜狐镜像：</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http://mirrors.sohu.com/centos/6/isos/</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http://mirrors.sohu.com/centos/7/isos/x86_64/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>下载好的镜像文件存于一个比较稳妥的目录下</p><p><img src="https://img.xbin.cn/blog/14_S9eHEk73LG.png" alt=""></p><blockquote><p>第二步：选中对应的虚拟机然后点击虚拟机选项，找到设置</p></blockquote><p><img src="https://img.xbin.cn/blog/1_i771qGMWfi.png" alt=""></p><blockquote><p>第二步：找到 <code>CD</code>、<code>DVD</code> 选项&gt;使用 <code>IOS</code> 镜像文件&gt;浏览&gt;选择的 <code>IOS</code> 镜像文件</p></blockquote><p><img src="https://img.xbin.cn/blog/3_DNzfLIw7th.png" alt=""></p><blockquote><p>第三步：开启虚拟机，开始对虚拟机特征进行设置</p></blockquote><p><img src="https://img.xbin.cn/blog/8_ylE4efLa9d.png" alt=""></p><blockquote><p>第四步：选择 <code>Install Centos 7</code></p></blockquote><p><img src="https://img.xbin.cn/blog/5_BguN7wK7Ed.png" alt=""></p><blockquote><p>第五步：选择安装过程中使用的提示语言</p></blockquote><p><img src="https://img.xbin.cn/blog/6_nBy-jU9Cp9.png" alt=""></p><blockquote><p>第六步：设置时区，时间和日期，与计算机日期一致即可</p></blockquote><p><img src="https://img.xbin.cn/blog/16_flikMQ6Dao.png" alt=""></p><p><img src="https://img.xbin.cn/blog/13_gWGWmqUbRJ.png" alt=""></p><blockquote><p>第七步：软件选择 <code>GNOME</code>，带有图形界面模式的 <code>Linux</code> 然后点击完成</p><p><strong>当前为了学习安装带图形化界面，后续只需要“最小安装”即可</strong></p></blockquote><p><img src="https://img.xbin.cn/blog/10_BYkT1YYJh8.png" alt=""></p><p><img src="https://img.xbin.cn/blog/7_BdJFPrOtHn.png" alt=""></p><blockquote><p>第八步：等待安装源和软件选择的支持检查</p></blockquote><p><img src="https://img.xbin.cn/blog/9_03AwuuWV31.png" alt=""></p><blockquote><p>第九步： 设置安装位置，核对信息，然后点击完成即可</p></blockquote><p><img src="https://img.xbin.cn/blog/15_sa-7VfWc6u.png" alt=""></p><p><img src="https://img.xbin.cn/blog/11_w7DSrlZUl4.png" alt=""></p><blockquote><p>第十步： 设置网络和主机名，开启以太网，注意主机名和当前主机 <code>IP</code> 信息</p></blockquote><p><img src="https://img.xbin.cn/blog/17_zqCXRawiN1.png" alt=""></p><p><img src="https://img.xbin.cn/blog/12_aZ5MUJgtZ-.png" alt=""></p><blockquote><p>第十一步： <code>KDUMP</code> 崩溃存储机制，可以关闭</p></blockquote><p><img src="https://img.xbin.cn/blog/19_hn7N5j5qle.png" alt=""></p><blockquote><p>第十二步：开始安装</p></blockquote><p><img src="https://img.xbin.cn/blog/21_nFEGHyfzx7.png" alt=""></p><blockquote><p>第十三步：设置超级管理员 <code>root</code> 用户的密码，配置完成，点击重启</p></blockquote><p><img src="https://img.xbin.cn/blog/20_m_9aC_SRzF.png" alt=""></p><p><img src="https://img.xbin.cn/blog/16_3d_tmv1D4W.png" alt=""></p><blockquote><p>第十四步：重启后，选择第一项，开启虚拟机</p></blockquote><p><img src="https://img.xbin.cn/blog/22_m2FS25EVcw.png" alt=""></p><blockquote><p>第十五步：第一次进入虚拟机，需要接受许可</p></blockquote><p><img src="https://img.xbin.cn/blog/14_IWD0l5uzEp.png" alt=""></p><p><img src="https://img.xbin.cn/blog/26_ow74w6Gxn1.png" alt=""></p><blockquote><p>第十六步： 选择汉语，然后前进</p></blockquote><p><img src="https://img.xbin.cn/blog/18_8sTOYWF4T8.png" alt=""></p><blockquote><p>第十七步：选择输入，汉语，然后前进</p></blockquote><p><img src="https://img.xbin.cn/blog/27_zoe6S1Hg1B.png" alt=""></p><blockquote><p>第十八步：位置服务，可以关闭，然后前进</p></blockquote><p><img src="https://img.xbin.cn/blog/24_f7evUbAwnJ.png" alt=""></p><blockquote><p>第十九步：选择时区，已经设置过，然后前进</p></blockquote><p><img src="https://img.xbin.cn/blog/23_FGfq9HZ7pg.png" alt=""></p><blockquote><p>第二十步：在线账号创建，选择跳过</p></blockquote><p><img src="https://img.xbin.cn/blog/29_iO9pRTz2gX.png" alt=""></p><blockquote><p>第二十一步：创建用于第一次登陆系统的普通用户账号，这里绝对不可以使用 <code>root</code> 作为用户名</p></blockquote><p><img src="https://img.xbin.cn/blog/25_7CA9gsZLk_.png" alt=""></p><blockquote><p>第二十二步： 设置普通账户密码</p></blockquote><p><img src="https://img.xbin.cn/blog/30_09Qd8hQeKq.png" alt=""></p><blockquote><p>第二十三步：进入系统后，点击关机按钮，找到用户，选择注销</p></blockquote><p><img src="https://img.xbin.cn/blog/33_nqXZCJuzA5.png" alt=""></p><p><img src="https://img.xbin.cn/blog/31_frNA-zGZZv.png" alt=""></p><blockquote><p>第二十四步：点击未列出，输入超级管理员的账号密码，以超级管理员身份登录，前面的用户设置重复一遍后，即可进入系统</p></blockquote><p><img src="https://img.xbin.cn/blog/28_rg1JOBOEbU.png" alt=""></p><p><img src="https://img.xbin.cn/blog/32_d_WRDqmK_U.png" alt=""></p><p><img src="https://img.xbin.cn/blog/01_o6r5DAKdE_.png" alt=""></p><blockquote><p>第二十五步：如果需要关机，一定要先将虚拟机关机或者挂起后，再关闭 <code>VMware</code>，然后关闭 <code>windows</code></p></blockquote><p><img src="https://img.xbin.cn/blog/02_xE5ZUpgFx1.png" alt=""></p><p>要想让鼠标从 <code>VMware</code> 的 虚拟中脱离出来，需要按快捷键 <code>ctrl</code>+<code>alt</code></p><h2 id="第五节-vmware-常见问题" tabindex="-1">第五节 <code>VMware</code> 常见问题 <a class="header-anchor" href="#第五节-vmware-常见问题" aria-label="Permalink to &quot;第五节 `VMware` 常见问题&quot;">​</a></h2><h3 id="问题-1" tabindex="-1">问题 <code>1</code> <a class="header-anchor" href="#问题-1" aria-label="Permalink to &quot;问题 `1`&quot;">​</a></h3><p>启动 <code>VM</code> 报 <code>0xc0000005</code>，这是与 <code>vindows Hyper-V</code> 服务冲突造成的</p><p><img src="https://img.xbin.cn/blog/06_IZKWqQBAmN.png" alt=""></p><p><code>1</code> 关闭以下服务</p><p><img src="https://img.xbin.cn/blog/34_y4OQm9Hm7P.png" alt=""></p><p><code>2</code> 以管理员方式运行以下命令</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bcdedit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hypervisorlaunchtype</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> off</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>3</code> 重启电脑</p><h3 id="问题-2" tabindex="-1">问题 <code>2</code> <a class="header-anchor" href="#问题-2" aria-label="Permalink to &quot;问题 `2`&quot;">​</a></h3><p>启动 <code>VMware</code> 蓝屏问题</p><p><code>1</code> 打开控制面板，点击卸载程序</p><p><img src="https://img.xbin.cn/blog/l2_HAmhEeDBO8.png" alt=""></p><p><code>2</code> 点击启用或者关闭 <code>Windows</code> 功能</p><p><img src="https://img.xbin.cn/blog/l1_TRu49JFdqM.png" alt=""></p><p><code>3</code> 勾选如下两个选项</p><p><img src="https://img.xbin.cn/blog/vm02_YppnWpeXN1.png" alt=""></p><h3 id="问题-3" tabindex="-1">问题 <code>3</code> <a class="header-anchor" href="#问题-3" aria-label="Permalink to &quot;问题 `3`&quot;">​</a></h3><ul><li><p>如果采用问题 <code>2</code> 方式，运行一段时间后还是蓝屏，到官网下载最新版本安装</p></li><li><p>如果还是不行，可以考虑使用其他虚拟化软件，比如 <code>VirtualBox</code></p></li><li><p>如果换软件还是出现问题，考虑重新安装 <code>Windows</code> 操作系统</p></li></ul><h3 id="问题-4-vmware-tools-安装" tabindex="-1">问题 <code>4 VMware tools</code> 安装 <a class="header-anchor" href="#问题-4-vmware-tools-安装" aria-label="Permalink to &quot;问题 `4 VMware tools` 安装&quot;">​</a></h3><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 切换yum源，系统自带下载源已经停止维护，切换成阿里源！！</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/yum.repos.d/CentOS-Base.repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://mirrors.aliyun.com/repo/Centos-7.repo</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> epel-release</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open-vm-tools</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open-vm-tools-desktop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div>',157)])])}const h=p(s,[["render",l]]);export{d as __pageData,h as default};
